import{_ as e,o as r,c as n,a3 as i}from"./chunks/framework.oxq6d-og.js";const m=JSON.parse('{"title":"Windows x64 ABI ve NThread","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/windows-x64-abi.md","filePath":"architecture/windows-x64-abi.md"}'),d={name:"architecture/windows-x64-abi.md"};function o(l,a,t,s,c,u){return r(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="windows-x64-abi-ve-nthread" tabindex="-1">Windows x64 ABI ve NThread <a class="header-anchor" href="#windows-x64-abi-ve-nthread" aria-label="Permalink to &quot;Windows x64 ABI ve NThread&quot;">​</a></h1><p>NThread, çağrının adresini bilmenin yanında Windows x64 çağrı sözleşmesine uygun bir register ve stack durumu kurmak zorundadır. Bu sayfa ABI&#39;nin genel kurallarını ve NThread&#39;in bugün uyguladığı kısmı ayırır; desteklenmeyen imzaları destekleniyormuş gibi yorumlamayın.</p><h2 id="ilk-dort-parametre-pozisyoneldir" tabindex="-1">İlk dört parametre pozisyoneldir <a class="header-anchor" href="#ilk-dort-parametre-pozisyoneldir" aria-label="Permalink to &quot;İlk dört parametre pozisyoneldir&quot;">​</a></h2><p>Windows x64&#39;te ilk dört parametrenin <strong>pozisyonu</strong> register slotunu belirler. Tamsayı/pointer slotları <code>RCX</code>, <code>RDX</code>, <code>R8</code>, <code>R9</code>; kayan nokta slotları aynı sıra numarasıyla <code>XMM0</code>–<code>XMM3</code> kullanır. Karışık imzada register numarası türden bağımsız olarak parametre konumudur: örneğin ikinci parametre <code>f64</code> ise <code>XMM1</code> slotundadır, <code>XMM0</code> değil.</p><p>NThread, ilk dört parametrede türden <code>f32</code>/<code>f64</code> olarak normalize edilenleri ilgili <code>XMM</code> slotuna yazar; aynı float bitlerini karşılık gelen genel amaçlı register alanına da kopyalar. Bu, NThread&#39;in somut çağrı kurulum davranışıdır; kullanıcı tarafında “tüm float&#39;lar ayrı bir register dizisinden sayılır” varsayımı yapılmamalıdır.</p><p>Beşinci ve sonraki parametreler stack slotlarına yazılır. Tamsayı/pointer dönüşü <code>RAX</code>&#39;tan, <code>f32</code>/<code>f64</code> dönüşü <code>XMM0</code>&#39;dan okunur.</p><h2 id="stack-ve-donus-zinciri" tabindex="-1">Stack ve dönüş zinciri <a class="header-anchor" href="#stack-ve-donus-zinciri" aria-label="Permalink to &quot;Stack ve dönüş zinciri&quot;">​</a></h2><p>Çağrı sahibi 32 byte shadow space ayırır ve çağrı sınırındaki 16-byte hizalamayı korur. NThread yakaladığı thread&#39;in özgün <code>RSP</code> değerinin altında bir çalışma alanı seçer; çağrı dönüşünü <code>add rsp, 0x28; ret</code> ve spin stub zinciriyle park noktasına geri getirir. Dörtten fazla argümanda, argüman sayısına uygun geçici bir <code>add rsp, 0x28 + N*8; ret</code> stub&#39;ı kullanır.</p><p>Bu düzenleme yalnızca NThread&#39;in kurduğu çağrı için geçerlidir. Hedef fonksiyonun kendi ABI&#39;si, varargs davranışı veya özel stack beklentisi farklıysa NThread bunu otomatik olarak düzeltemez.</p><h2 id="pratik-sınırlar" tabindex="-1">Pratik sınırlar <a class="header-anchor" href="#pratik-sınırlar" aria-label="Permalink to &quot;Pratik sınırlar&quot;">​</a></h2><ul><li>İmzayı, özellikle parametre sırasını ve <code>f32</code>/<code>f64</code> ayrımını doğrulayın.</li><li>Varargs, struct-by-value, SIMD/vector türleri ve standart dışı calling convention&#39;lar için önce küçük bir kontrollü test yazın.</li><li>Geri dönmeyen ya da uzun süre bloklanan fonksiyonlar park noktasına dönmez; NThread çağrısı için uygun değildir.</li><li><code>expectedRsp</code> ayarlanmışsa NThread hem async <code>call()</code> hem <code>callSync()</code> dönüşünde gerçek <code>RSP</code> değerini denetler; uyarı, çağrının güvenle sürdürülebileceği anlamına gelmez.</li></ul><p>Çağrıyı önce argümansız veya basit tamsayı imzalı, yan etkisi düşük bir fonksiyonla doğrulamak en güvenli başlangıçtır. Çağrı akışının geri kalanı için <a href="/exoproc/previews/feature-docs/nthread/call-lifecycle">NThread yaşam döngüsüne</a> bakın.</p>',12)])])}const y=e(d,[["render",o]]);export{m as __pageData,y as default};
